import java.util.*
import kotlin.math.*

fun solve(nums: Array<Long>, queries: Array<Array<Long>>): Array<Long> {
    val n = nums.size
    val q = queries.size
    val blockSize = sqrt(n.toDouble()).toInt()

    val sortedIndices = queries.indices.sortedWith { i, j ->
        val iBlock = (queries[i][0] / blockSize).toInt()
        val jBlock = (queries[j][0] / blockSize).toInt()
        if (iBlock != jBlock) {
            iBlock.compareTo(jBlock)
        } else {
            if (iBlock % 2 == 0) {
                queries[i][1].compareTo(queries[j][1])
            } else {
                queries[j][1].compareTo(queries[i][1])
            }
        }
    }

    data class State(val freq: Int, val element: Long)

    val stateSet = TreeSet<State>(compareBy({ -it.freq }, { it.element }))
    val freqMap = mutableMapOf<Long, Int>()

    var curL = 0
    var curR = -1
    val ans = Array<Long>(q) { -1 }

    fun addElement(index: Int) {
        val x = nums[index]
        val oldFreq = freqMap.getOrDefault(x, 0)
        if (oldFreq > 0) {
            stateSet.remove(State(oldFreq, x))
        }
        val newFreq = oldFreq + 1
        freqMap[x] = newFreq
        stateSet.add(State(newFreq, x))
    }

    fun removeElement(index: Int) {
        val x = nums[index]
        val oldFreq = freqMap[x]!!
        stateSet.remove(State(oldFreq, x))
        val newFreq = oldFreq - 1
        if (newFreq > 0) {
            freqMap[x] = newFreq
            stateSet.add(State(newFreq, x))
        } else {
            freqMap.remove(x)
        }
    }

    for (i in sortedIndices) {
        val l = queries[i][0].toInt()
        val r = queries[i][1].toInt()
        val threshold = queries[i][2]

        while (curR < r) {
            curR++
            addElement(curR)
        }
        while (curR > r) {
            removeElement(curR)
            curR--
        }
        while (curL < l) {
            removeElement(curL)
            curL++
        }
        while (curL > l) {
            curL--
            addElement(curL)
        }

        if (stateSet.isNotEmpty()) {
            val candidate = stateSet.first()
            if (candidate.freq >= threshold) {
                ans[i] = candidate.element
            } else {
                ans[i] = -1
            }
        }
    }

    return ans
}
