import java.util.*

fun solve(nums: Array<Long>, queries: Array<Array<Long>>): Array<Long> {
    val n = nums.size
    val q = queries.size
    if (q == 0) return emptyArray()

    val BLOCK_SIZE = Math.sqrt(n.toDouble()).toInt()

    data class Query(val l: Int, val r: Int, val threshold: Int, val idx: Int)

    val sortedQueries = Array(q) { i ->
        val l = queries[i][0].toInt()
        val r = queries[i][1].toInt()
        val threshold = queries[i][2].toInt()
        Query(l, r, threshold, i)
    }

    sortedQueries.sortWith(compareBy(
        { it.l / BLOCK_SIZE },
        { it.r }
    ))

    val freq = hashMapOf<Long, Int>()
    val buckets = arrayOfNulls<TreeSet<Long>>(n + 1)
    val activeFreq = TreeSet<Int>(Collections.reverseOrder())

    var curL = 0
    var curR = -1
    val ans = Array(q) { 0L }

    fun add(pos: Int) {
        val x = nums[pos]
        val oldFreq = freq.getOrDefault(x, 0)
        val newFreq = oldFreq + 1

        freq[x] = newFreq

        if (oldFreq > 0) {
            buckets[oldFreq]?.remove(x)
            if (buckets[oldFreq]?.isEmpty() == true) {
                activeFreq.remove(oldFreq)
            }
        }

        if (buckets[newFreq] == null) {
            buckets[newFreq] = TreeSet()
        }
        buckets[newFreq]?.add(x)
        if (buckets[newFreq]?.size == 1) {
            activeFreq.add(newFreq)
        }
    }

    fun remove(pos: Int) {
        val x = nums[pos]
        val oldFreq = freq[x] ?: return
        val newFreq = oldFreq - 1

        if (newFreq == 0) {
            freq.remove(x)
        } else {
            freq[x] = newFreq
        }

        buckets[oldFreq]?.remove(x)
        if (buckets[oldFreq]?.isEmpty() == true) {
            activeFreq.remove(oldFreq)
        }

        if (newFreq > 0) {
            if (buckets[newFreq] == null) {
                buckets[newFreq] = TreeSet()
            }
            buckets[newFreq]?.add(x)
            if (buckets[newFreq]?.size == 1) {
                activeFreq.add(newFreq)
            }
        }
    }

    for (query in sortedQueries) {
        val (l, r, threshold, idx) = query

        while (curR < r) add(++curR)
        while (curR > r) remove(curR--)
        while (curL < l) remove(curL++)
        while (curL > l) add(--curL)

        val globalMax = if (activeFreq.isNotEmpty()) activeFreq.first() else 0

        if (globalMax < threshold) {
            ans[idx] = -1
        } else {
            ans[idx] = buckets[globalMax]?.first() ?: -1
        }
    }

    return ans
}
